import { ChatOpenAI } from "langchain/chat_models/openai";
import { LLMChain } from "langchain/chains";
import { Vex } from "vex-sdk";

const llm = new ChatOpenAI({ modelName: "gpt-4" });
const chain = new LLMChain({ llm, prompt: policyChatPrompt });

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

export async function safePolicyChat(input: string, history: string[]) {
  const fullContext = history.slice(-10).join('\n') + '\n' + input;

  const result = await vex.verify({
    checks: ["context_overflow", "pii_exposure", "token_limit=128000"],
    payload: async () => {
      return await chain.call({ input: fullContext });
    }
  });

  return result.output;
}
